function krumo(){}
krumo.reclass=function(el,className){el.classList.add(className)}
krumo.unclass=function(el,className){el.classList.remove(className)}
krumo.toggle=function(event){var elem=event.target.closest(".krumo-expand");var ctrl=event.ctrlKey;if(elem===null){event.stopPropagation();return}
var is_expanded=!elem.classList.contains("krumo-opened");if(ctrl){if(is_expanded){krumo.expand_all(elem)}else{krumo.collapse_all(elem)}}else{if(is_expanded){krumo.expand(elem)}else{krumo.collapse(elem)}}
event.stopPropagation()}
krumo.expand=function(el){paren=el.parentNode;nest=paren.querySelector(".krumo-nest");exp=paren.querySelector(".krumo-expand");nest.style.display='block';krumo.reclass(exp,"krumo-opened")}
krumo.collapse=function(el){paren=el.parentNode;nest=paren.querySelector(".krumo-nest");exp=paren.querySelector(".krumo-expand");nest.style.display='none';krumo.unclass(exp,"krumo-opened")}
krumo.expand_all=function(el){paren=el.parentNode;nest=paren.querySelectorAll(".krumo-nest");exp=paren.querySelectorAll(".krumo-expand");nest.forEach(function(item,i){item.style.display='block'});exp.forEach(function(item,i){krumo.reclass(item,"krumo-opened")})}
krumo.collapse_all=function(el){paren=el.parentNode;nest=paren.querySelectorAll(".krumo-nest");exp=paren.querySelectorAll(".krumo-expand");nest.forEach(function(item,i){item.style.display='none'});exp.forEach(function(item,i){krumo.unclass(item,"krumo-opened")})}
krumo.over=function(el){krumo.reclass(el,'krumo-hover')}
krumo.out=function(el){krumo.unclass(el,'krumo-hover')}
function qsa(search){var elems=document.querySelectorAll(search);return elems}
function init_click(){var elems=qsa('.krumo-expand');elems.forEach(function(el){el.parentNode.addEventListener("click",krumo.toggle)})}
document.addEventListener("DOMContentLoaded",function(){init_click()})